    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = [0];

    for (let start = 0; start < n; start++) {
        const visited = 1 << start;
        const path: number[] = [start];
        dfs(path, visited, adj, label, maxLen);
    }

    return maxLen[0];
}

function dfs(path: number[], visited: number, adj: number[][], label: string, maxLen: number[]): void {
    const s = path.map(node => label[node]).join('');
    if (s === s.split('').reverse().join('')) {
        maxLen[0] = Math.max(maxLen[0], path.length);
    }

    if (path.length === n) {
        return;
    }

    const lastNode = path[path.length - 1];
    for (const neighbor of adj[lastNode]) {
        if (!(visited & (1 << neighbor))) {
            const newVisited = visited | (1 << neighbor);
            const newPath = [...path, neighbor];
            dfs(newPath, newVisited, adj, label, maxLen);
        }
    }
}
